import{_ as a,c as s,o as i,ak as t,al as o}from"./chunks/framework.DHLlVITf.js";const m=JSON.parse('{"title":"AireAssert Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireassert-v1-3-2.md","filePath":"aireblock-releases/aireassert-v1-3-2.md","lastUpdated":1784709682000}'),r={name:"aireblock-releases/aireassert-v1-3-2.md"};function l(n,e,c,d,h,u){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="aireassert-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+o+'"> AireAssert Release Notes</span> <a class="header-anchor" href="#aireassert-release-notes" aria-label="Permalink to “AireAssert Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 1.3.2<br><strong>Release Date:</strong> 15 July 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Clearer Subject Assertion Error Messages (AA-972)</li><li>Retryable Subject Assertions (AA-973)</li><li>Reliable Saved Values in Complex Imports (AA-974)</li><li>Reference AireFrame Fields by Label (AA-975)</li><li>Clearer Errors for Malformed Example Blocks (AA-977)</li><li>Query Widget Data Across Dashboards (AA-980)</li><li>Improved Deployment Pipeline Reliability (AA-982)</li><li>Faster, More Reliable Chart Hosting (AA-983)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Fixed Validation Messages on Other Controls (AA-969)</li><li>Fixed Scenario Discovery for Imported Features (AA-970)</li><li>Fixed Validation Assertions on Toggle Controls (AA-978)</li><li>Fixed Retry Timeout Reset on Save (AA-979)</li><li>Fixed Widget Action Execution (AA-981)</li></ul><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="clearer-subject-assertion-error-messages-aa-972" tabindex="-1">Clearer Subject Assertion Error Messages (AA-972) <a class="header-anchor" href="#clearer-subject-assertion-error-messages-aa-972" aria-label="Permalink to “Clearer Subject Assertion Error Messages (AA-972)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>When a subject assertion failed, the error shown was a raw internal message that didn&#39;t clearly explain what had gone wrong. Failures now show a descriptive message stating that no subject matched the filtered fields, along with the field values used.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>When a test fails on a subject assertion, you&#39;ll immediately see which field values didn&#39;t match, helping you diagnose issues faster without digging through logs.</p></div><h4 id="retryable-subject-assertions-aa-973" tabindex="-1">Retryable Subject Assertions (AA-973) <a class="header-anchor" href="#retryable-subject-assertions-aa-973" aria-label="Permalink to “Retryable Subject Assertions (AA-973)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Subject assertions can now be retried to account for processing time within AireFrame. The retry duration is configurable via a setting in the testset configuration file.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Your tests are less likely to fail due to timing issues, as you can now allow extra time for AireFrame to process data before an assertion is checked.</p></div><h4 id="reliable-saved-values-in-complex-imports-aa-974" tabindex="-1">Reliable Saved Values in Complex Imports (AA-974) <a class="header-anchor" href="#reliable-saved-values-in-complex-imports-aa-974" aria-label="Permalink to “Reliable Saved Values in Complex Imports (AA-974)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Saved values were sometimes coming through blank when complex feature imports were used. This has been investigated and fixed.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Saved values now carry through correctly in your tests, even when your feature files include complex imports.</p></div><h4 id="reference-aireframe-fields-by-label-aa-975" tabindex="-1">Reference AireFrame Fields by Label (AA-975) <a class="header-anchor" href="#reference-aireframe-fields-by-label-aa-975" aria-label="Permalink to “Reference AireFrame Fields by Label (AA-975)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Previously, fields could only be referenced using their field key. Tenant configuration is now retrieved on login, allowing fields to be referenced by label as well.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now write your tests using field labels rather than needing to know internal field keys, making your feature files easier to read and maintain.</p></div><h4 id="clearer-errors-for-malformed-example-blocks-aa-977" tabindex="-1">Clearer Errors for Malformed Example Blocks (AA-977) <a class="header-anchor" href="#clearer-errors-for-malformed-example-blocks-aa-977" aria-label="Permalink to “Clearer Errors for Malformed Example Blocks (AA-977)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>An example block missing its start pipe previously caused a failure that was not reported correctly during test execution. This is now detected during feature compilation, and the testset is reported as CouldNotStart with a descriptive error.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>If an example block in your feature file is malformed, you&#39;ll get a clear, upfront error explaining the problem instead of a confusing test failure.</p></div><h4 id="query-widget-data-across-dashboards-aa-980" tabindex="-1">Query Widget Data Across Dashboards (AA-980) <a class="header-anchor" href="#query-widget-data-across-dashboards-aa-980" aria-label="Permalink to “Query Widget Data Across Dashboards (AA-980)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Widget data can now be queried from additional dashboards in AireFrame when making assertions, across both Subject List and Subject Detail sections. Widgets can also be referenced by ID rather than title where duplicate titles exist.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now assert against widget data no matter which dashboard it lives on, and you can reliably target the right widget even when multiple widgets share the same title.</p></div><h4 id="improved-deployment-pipeline-reliability-aa-982" tabindex="-1">Improved Deployment Pipeline Reliability (AA-982) <a class="header-anchor" href="#improved-deployment-pipeline-reliability-aa-982" aria-label="Permalink to “Improved Deployment Pipeline Reliability (AA-982)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The deployment pipeline has been updated to use a new Bitbucket access method, resolving repository access issues that were blocking deployments.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>This keeps AireAssert releases flowing smoothly, so you continue to receive updates and fixes without disruption.</p></div><h4 id="faster-more-reliable-chart-hosting-aa-983" tabindex="-1">Faster, More Reliable Chart Hosting (AA-983) <a class="header-anchor" href="#faster-more-reliable-chart-hosting-aa-983" aria-label="Permalink to “Faster, More Reliable Chart Hosting (AA-983)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Helm chart publishing has moved from Git-based hosting to S3, in line with the approach used for AireGlu, resolving publishing failures.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>This change supports more reliable behind-the-scenes delivery of AireAssert updates to you.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="fixed-validation-messages-on-other-controls-aa-969" tabindex="-1">Fixed Validation Messages on Other Controls (AA-969) <a class="header-anchor" href="#fixed-validation-messages-on-other-controls-aa-969" aria-label="Permalink to “Fixed Validation Messages on Other Controls (AA-969)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Validation messages were not working correctly on other controls. This has been fixed.</p></div><h4 id="fixed-scenario-discovery-for-imported-features-aa-970" tabindex="-1">Fixed Scenario Discovery for Imported Features (AA-970) <a class="header-anchor" href="#fixed-scenario-discovery-for-imported-features-aa-970" aria-label="Permalink to “Fixed Scenario Discovery for Imported Features (AA-970)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>When more than one feature was imported into another, referencing a scenario from the second imported feature could not be found, causing the testset to fail compilation. Scenario discovery across imported features has been fixed.</p></div><h4 id="fixed-validation-assertions-on-toggle-controls-aa-978" tabindex="-1">Fixed Validation Assertions on Toggle Controls (AA-978) <a class="header-anchor" href="#fixed-validation-assertions-on-toggle-controls-aa-978" aria-label="Permalink to “Fixed Validation Assertions on Toggle Controls (AA-978)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Assertions checking that a control does not have a validation message were failing when pointed at Toggle Controls. This has been fixed.</p></div><h4 id="fixed-retry-timeout-reset-on-save-aa-979" tabindex="-1">Fixed Retry Timeout Reset on Save (AA-979) <a class="header-anchor" href="#fixed-retry-timeout-reset-on-save-aa-979" aria-label="Permalink to “Fixed Retry Timeout Reset on Save (AA-979)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The AssertionRetryTimeout value in a testset&#39;s configuration was being reset to zero after synchronising the repository and saving a file change in the UI. This has been fixed so the configured value is retained.</p></div><h4 id="fixed-widget-action-execution-aa-981" tabindex="-1">Fixed Widget Action Execution (AA-981) <a class="header-anchor" href="#fixed-widget-action-execution-aa-981" aria-label="Permalink to “Fixed Widget Action Execution (AA-981)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>An AireFrame Widget Action was found during test execution but was not recognised as executable, causing validation to fail. This has been fixed.</p></div>',46)])])}const b=a(r,[["render",l]]);export{m as __pageData,b as default};
